@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username', '')
    password = data.get('password', '')
    email = data.get('email', '')
    
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', '')
    
    logging.info(
        f"REGISTER_ATTEMPT - Username: {username} - "
        f"Email: {email} - "
        f"IP: {ip_address} - "
        f"User-Agent: {user_agent}"
    )
    
    if username in users_db:
        logging.warning(f"REGISTER_FAILED - Username already exists: {username}")
        return jsonify({
            'success': False,
            'message': 'Username already exists'
        }), 400
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    users_db[username] = {
        'password_hash': password_hash,
        'email': email
    }
    
    logging.info(f"REGISTER_SUCCESS - Username: {username} - Email: {email}")
    
    return jsonify({
        'success': True,
        'message': 'Registration successful'
    }), 201


@app.route('/api/logout', methods=['POST'])
def logout():
    data = request.get_json()
    session_token = data.get('session_token', '')
    
    ip_address = request.remote_addr
    
    if session_token in sessions:
        username = sessions[session_token]
        del sessions[session_token]
        logging.info(f"LOGOUT - Username: {username} - IP: {ip_address}")
        return jsonify({
            'success': True,
            'message': 'Logout successful'
        }), 200
    
    return jsonify({
        'success': False,
        'message': 'Invalid session'
    }), 401


@app.route('/api/verify', methods=['POST'])
def verify():
    data = request.get_json()
    session_token = data.get('session_token', '')
    
    if session_token in sessions:
        username = sessions[session_token]
        return jsonify({
            'success': True,
            'username': username
        }), 200
    
    return jsonify({
        'success': False,
        'message': 'Invalid session'
    }), 401


